module adder_pipe_64bit(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [63:0] result,
    output o_en
);

reg [63:0] reg_adda, reg_addb;
reg [63:0] reg_sum;
reg reg_en;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg_adda <= 64'b0;
        reg_addb <= 64'b0;
        reg_sum <= 64'b0;
        reg_en <= 1'b0;
    end else if (i_en) begin
        reg_adda <= adda;
        reg_addb <= addb;
        reg_sum <= adda + addb;
        reg_en <= 1'b1;
    end else begin
        reg_sum <= 64'b0;
        reg_en <= 1'b0;
    end
end

assign result = reg_sum;
assign o_en = reg_en;

endmodule
